import heapq
import math
from collections import defaultdict

def agent_step(state, history):
    def heuristic(a, b):
        return abs(a[0] - b[0]) + abs(a[1] - b[1])

    def a_star_search(start, goal, walls, blocks, success_weights):
        frontier = []
        heapq.heappush(frontier, (0, start))
        came_from = {}
        cost_so_far = {}
        came_from[start] = None
        cost_so_far[start] = 0

        while frontier:
            _, current = heapq.heappop(frontier)

            if current == goal:
                break

            for dx, dy in [(-3, 0), (3, 0), (0, -3), (0, 3)]:  # Left, Right, Up, Down
                next_step = (current[0] + dx, current[1] + dy)
                if next_step in walls or next_step in blocks:
                    continue
                base_cost = 1
                if next_step in success_weights and success_weights[next_step] > 0:
                    base_cost *= 0.8  # Reward successful paths
                new_cost = cost_so_far[current] + base_cost
                if next_step not in cost_so_far or new_cost < cost_so_far[next_step]:
                    cost_so_far[next_step] = new_cost
                    priority = new_cost + heuristic(goal, next_step)
                    heapq.heappush(frontier, (priority, next_step))
                    came_from[next_step] = current

        if goal not in came_from:
            return None
        current = goal
        path = []
        while current != start:
            path.append(current)
            current = came_from[current]
        path.reverse()
        return path

    def get_move_direction(from_pos, to_pos):
        if from_pos[0] < to_pos[0]:
            return "MOVE_RIGHT"
        elif from_pos[0] > to_pos[0]:
            return "MOVE_LEFT"
        elif from_pos[1] < to_pos[1]:
            return "MOVE_DOWN"
        elif from_pos[1] > to_pos[1]:
            return "MOVE_UP"
        return None

    def analyze_history(history):
        direction_success = defaultdict(int)
        direction_failures = defaultdict(int)
        for turn in history:
            if "action" in turn and turn["action"].get("action") in ["MOVE_RIGHT", "MOVE_LEFT", "MOVE_UP", "MOVE_DOWN"]:
                action_dir = turn["action"]["action"]
                if turn.get("moved", False):
                    direction_success[action_dir] += 1
                else:
                    direction_failures[action_dir] += 1
        success_weights = {}
        for pos in [tuple(turn["state"]["player"]["position"]) for turn in history if turn.get("moved", False)]:
            last_action = history[history.index(turn) - 1]["action"]["action"] if history.index(turn) > 0 else None
            if last_action:
                success_weights[pos] = direction_success.get(last_action, 0)
        return success_weights, direction_success, direction_failures

    def is_stuck(history):
        return len(history) >= 3 and not any(turn.get("moved", False) for turn in history[-3:])

    player_pos = tuple(state["player"]["position"])
    goals = state["objects"]["goals"]
    walls = set(tuple(wall["position"]) for wall in state["objects"]["walls"])
    blocks = set(tuple(block["position"]) for block in state["objects"]["blocks"])

    success_weights, direction_success, direction_failures = analyze_history(history)

    # Level 1 specific strategy
    if state["level"]["current"] == 1:
        if player_pos == (9, 21):  # Starting position for Piece A
            return {"action": "MOVE_LEFT"}  # Move left towards [3,21] or [0,21]
        elif player_pos[0] > 3 and player_pos[1] == 21:
            return {"action": "MOVE_LEFT"}  # Continue moving left
        elif player_pos == (3, 21):
            if not state["movement"]["down_blocked"] or len(history) % 5 == 0:  # Probe MOVE_DOWN
                return {"action": "MOVE_DOWN"}
            else:
                return {"action": "MOVE_LEFT"}  # Fallback
        elif player_pos == (0, 21):
            if not state["movement"]["down_blocked"] or len(history) % 5 == 0:  # Probe MOVE_DOWN
                return {"action": "MOVE_DOWN"}
            else:
                return {"action": "MOVE_LEFT"}  # Fallback
        else:
            # After probing, try to reach goal
            if goals:
                goal_pos = tuple(goals[0]["position"])
                path = a_star_search(player_pos, goal_pos, walls, blocks, success_weights)
                if path:
                    next_step = path[0]
                    return {"action": get_move_direction(player_pos, next_step)}

    # General strategy for other levels
    if goals and state["resources"]["steps_remaining"] > 0:
        goal_pos = tuple(goals[0]["position"])
        path = a_star_search(player_pos, goal_pos, walls, blocks, success_weights)
        if path:
            next_step = path[0]
            return {"action": get_move_direction(player_pos, next_step)}

    if is_stuck(history) and state["level"]["current"] != 1:  # Only switch if not Level 1
        selectables = state["objects"]["selectables"]
        if selectables and goals:
            best_selectable = min([s for s in selectables if tuple(s["position"]) != player_pos], key=lambda s: heuristic(tuple(s["position"]), tuple(goals[0]["position"])))
            return {"action": "CLICK", "target_position": best_selectable["position"]}

    # Fallback: Choose direction with highest success rate
    directions = ["MOVE_RIGHT", "MOVE_LEFT", "MOVE_UP", "MOVE_DOWN"]
    net_success = {dir: direction_success.get(dir, 0) - direction_failures.get(dir, 0) for dir in directions}
    if net_success:
        best_direction = max(net_success, key=net_success.get)
        return {"action": best_direction}

    # Final fallback
    cycle = ["MOVE_RIGHT", "MOVE_DOWN", "MOVE_LEFT", "MOVE_UP"]
    step = len(history)
    return {"action": cycle[step % len(cycle)]}
